import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getEventById, getSlotsByEvent } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const TYPE_ICONS = { MOVIE: '🎬', CONCERT: '🎵', EVENT: '🎪' };
const TYPE_COLOR = { MOVIE: '#2563a8', CONCERT: '#c97d1a', EVENT: '#1a8f63' };

const EventDetailPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [event, setEvent]               = useState(null);
  const [slots, setSlots]               = useState([]);
  const [loading, setLoading]           = useState(true);
  const [selectedDate, setSelectedDate] = useState('');

  useEffect(() => {
    const load = async () => {
      try {
        const [evRes, slRes] = await Promise.all([
          getEventById(id),
          getSlotsByEvent(id),
        ]);
        const ev = evRes.data?.data || null;
        const sl = Array.isArray(slRes.data?.data) ? slRes.data.data : [];
        setEvent(ev);
        setSlots(sl);
        if (sl.length > 0) setSelectedDate(sl[0].showDate);
      } catch {
        toast.error('Failed to load event details');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [id]);

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;
  if (!event) return (
    <div className="empty-state" style={{ marginTop: '80px' }}>
      <div className="empty-state-icon">🎭</div>
      <h3>Event not found</h3>
      <button onClick={() => navigate('/')} className="btn btn-primary" style={{ marginTop: '16px' }}>Back to Browse</button>
    </div>
  );

  const color         = TYPE_COLOR[event.type] || '#9c9285';
  const icon          = TYPE_ICONS[event.type] || '🎪';
  const isEventActive = event.status === 'ACTIVE';
  const dates         = [...new Set(slots.map((s) => s.showDate))].sort();

  // Show ALL slots for the selected date (including cancelled/housefull) — don't hide them
  const filteredSlots = selectedDate ? slots.filter((s) => s.showDate === selectedDate) : slots;

  const handleBook = (slotId, slotStatus) => {
    if (!user) { toast.error('Please login to book'); navigate('/login'); return; }
    if (!isEventActive) {
      toast.error(`Booking unavailable — this event is ${event.status}`); return;
    }
    if (slotStatus === 'HOUSEFULL') { toast.error('This show is housefull'); return; }
    if (slotStatus === 'CANCELLED') { toast.error('This show has been cancelled'); return; }
    navigate(`/book/${slotId}`);
  };

  return (
    <div style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>

      {/* Hero banner */}
      <div style={{ background: 'linear-gradient(135deg,#fff8f5 0%,#fef2ea 100%)', borderBottom: '1.5px solid var(--border)', padding: '28px 0 36px' }}>
        <div className="container">
          <button onClick={() => navigate(-1)} className="btn btn-ghost btn-sm" style={{ marginBottom: '18px', paddingLeft: 0 }}>
            ← Back to Browse
          </button>

          <div style={{ display: 'flex', gap: '24px', alignItems: 'flex-start', flexWrap: 'wrap' }}>
            <div style={{ width: 96, height: 96, background: 'white', borderRadius: '18px', border: `2px solid ${color}40`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '44px', boxShadow: 'var(--shadow)', flexShrink: 0 }}>
              {icon}
            </div>

            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', gap: '8px', marginBottom: '12px', flexWrap: 'wrap', alignItems: 'center' }}>
                <span style={{ fontSize: '12px', fontWeight: 700, color, background: `${color}15`, padding: '3px 10px', borderRadius: '20px' }}>
                  {icon} {event.type}
                </span>
                <span style={{
                  fontSize: '11px', fontWeight: 700, padding: '3px 9px', borderRadius: '20px',
                  background: event.status === 'ACTIVE' ? '#e8fff5' : event.status === 'CANCELLED' ? '#fff0f0' : '#f0f0f0',
                  color:      event.status === 'ACTIVE' ? '#1a8f63' : event.status === 'CANCELLED' ? '#b91c1c'  : '#888',
                }}>
                  {event.status}
                </span>
                {event.genre    && event.genre.split(',').map((g) => <span key={g} className="badge badge-muted">{g.trim()}</span>)}
                {event.language && event.language.split(',').map((l) => <span key={l} className="badge badge-muted">{l.trim()}</span>)}
              </div>

              <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 'clamp(1.6rem,3vw,2.8rem)', fontWeight: 400, marginBottom: '10px', color: 'var(--text-primary)' }}>
                {event.name}
              </h1>

              {event.summary && (
                <p style={{ color: 'var(--text-secondary)', lineHeight: 1.7, maxWidth: '600px', fontSize: '15px', marginBottom: '14px' }}>
                  {event.summary}
                </p>
              )}

              <div style={{ display: 'flex', gap: '28px', flexWrap: 'wrap' }}>
                {event.duration        && <Detail label="Duration"  value={event.duration} />}
                {event.categoryName    && <Detail label="Category"  value={event.categoryName} />}
                {event.organiser?.name && <Detail label="Organiser" value={event.organiser.name} />}
              </div>

              {/* Event not active banner */}
              {!isEventActive && (
                <div style={{
                  marginTop: '16px', display: 'inline-flex', alignItems: 'center', gap: '8px',
                  padding: '10px 16px', borderRadius: '8px',
                  background: event.status === 'CANCELLED' ? 'rgba(185,28,28,0.08)' : 'rgba(156,146,133,0.1)',
                  border: `1.5px solid ${event.status === 'CANCELLED' ? 'rgba(185,28,28,0.25)' : 'var(--border)'}`,
                  color: event.status === 'CANCELLED' ? 'var(--red)' : 'var(--text-muted)',
                  fontSize: '13px', fontWeight: 600,
                }}>
                  {event.status === 'CANCELLED' ? '🚫' : '✅'}
                  {event.status === 'CANCELLED'
                    ? 'This event has been cancelled. All shows are unavailable.'
                    : 'This event has completed. Bookings are closed.'}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Shows section */}
      <div className="container" style={{ paddingTop: '36px', paddingBottom: '48px' }}>
        <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.8rem', fontWeight: 400, marginBottom: '6px' }}>
          Choose a Show
        </h2>
        <p style={{ color: 'var(--text-muted)', fontSize: '14px', marginBottom: '24px' }}>
          {slots.length} show{slots.length !== 1 ? 's' : ''} scheduled
        </p>

        {slots.length === 0 ? (
          <div className="empty-state">
            <div className="empty-state-icon">📅</div>
            <h3>No Shows Scheduled</h3>
            <p style={{ fontSize: '13px' }}>Check back later for upcoming shows</p>
          </div>
        ) : (
          <>
            {/* Date tabs */}
            <div style={{ display: 'flex', gap: '8px', marginBottom: '28px', overflowX: 'auto', paddingBottom: '6px' }}>
              {dates.map((date) => {
                const d          = new Date(date + 'T00:00:00');
                const isSelected = selectedDate === date;
                // if ALL slots on this date are cancelled, dim the tab
                const allCancelled = slots.filter((s) => s.showDate === date).every((s) => s.slotStatus === 'CANCELLED');
                return (
                  <button key={date} onClick={() => setSelectedDate(date)}
                    style={{
                      padding: '10px 22px', borderRadius: '10px', border: '1.5px solid',
                      flexShrink: 0, cursor: 'pointer', transition: 'var(--transition)',
                      fontFamily: 'var(--font-body)', fontWeight: 600, fontSize: '13px',
                      opacity: allCancelled ? 0.5 : 1,
                      borderColor: isSelected ? 'var(--accent)' : 'var(--border)',
                      background:  isSelected ? 'var(--accent-dim)' : 'var(--bg-card)',
                      color:       isSelected ? 'var(--accent)'     : 'var(--text-secondary)',
                      boxShadow:   isSelected ? 'var(--shadow-accent)' : 'var(--shadow-sm)',
                    }}>
                    <div style={{ fontSize: '12px', opacity: 0.7 }}>{d.toLocaleDateString('en-IN', { weekday: 'short' })}</div>
                    <div>{d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}</div>
                    {allCancelled && <div style={{ fontSize: '10px', color: 'var(--red)', fontWeight: 700, marginTop: '2px' }}>Cancelled</div>}
                  </button>
                );
              })}
            </div>

            {/* Slot grid — show ALL slots including cancelled/housefull */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(200px,1fr))', gap: '14px' }}>
              {filteredSlots.map((slot) => (
                <SlotCard
                  key={slot.slotId}
                  slot={slot}
                  eventActive={isEventActive}
                  eventStatus={event.status}
                  onBook={() => handleBook(slot.slotId, slot.slotStatus)}
                />
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

// ── Slot Card ─────────────────────────────────────────────────────────────────
const SlotCard = ({ slot, eventActive, eventStatus, onBook }) => {
  const isAvailable = slot.slotStatus === 'AVAILABLE';
  const isHousefull = slot.slotStatus === 'HOUSEFULL';
  const isCancelled = slot.slotStatus === 'CANCELLED';

  // Can only book if event is ACTIVE and slot is AVAILABLE
  const canBook = eventActive && isAvailable;

  // Button label logic
  const buttonLabel = isCancelled ? 'Cancelled'
    : !eventActive   ? (eventStatus === 'CANCELLED' ? 'Cancelled' : 'Completed')
    : isHousefull    ? 'Housefull'
    : 'Book Now';

  // Button color logic
  const buttonStyle = isCancelled || (eventStatus === 'CANCELLED')
    ? { background: '#b91c1c', opacity: 0.7 }
    : isHousefull
    ? { background: 'var(--gold)', opacity: 0.8 }
    : !eventActive
    ? { background: 'var(--text-muted)', opacity: 0.6 }
    : {};

  // Card overlay style for cancelled
  const cardOpacity = isCancelled || !eventActive ? 0.65 : 1;

  return (
    <div className="card" style={{
      padding: '20px', transition: 'var(--transition)', opacity: cardOpacity,
      position: 'relative', overflow: 'hidden',
      border: isCancelled ? '1.5px solid rgba(185,28,28,0.25)' : undefined,
    }}
      onMouseEnter={(e) => { if (canBook) { e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = 'var(--shadow-lg)'; }}}
      onMouseLeave={(e) => { e.currentTarget.style.transform = ''; e.currentTarget.style.boxShadow = ''; }}
    >
      {/* Cancelled diagonal ribbon */}
      {isCancelled && (
        <div style={{
          position: 'absolute', top: 10, right: -20, background: '#b91c1c',
          color: 'white', fontSize: '9px', fontWeight: 800, padding: '3px 24px',
          transform: 'rotate(35deg)', letterSpacing: '0.08em', zIndex: 1,
        }}>
          CANCELLED
        </div>
      )}

      {/* Housefull ribbon */}
      {isHousefull && (
        <div style={{
          position: 'absolute', top: 10, right: -20, background: 'var(--gold)',
          color: 'white', fontSize: '9px', fontWeight: 800, padding: '3px 24px',
          transform: 'rotate(35deg)', letterSpacing: '0.08em', zIndex: 1,
        }}>
          HOUSEFULL
        </div>
      )}

      {/* Time */}
      <div style={{ marginBottom: '12px' }}>
        <div style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 400, color: 'var(--text-primary)', lineHeight: 1 }}>
          {slot.startTime?.slice(0, 5)}
        </div>
        <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px' }}>
          ends {slot.endTime?.slice(0, 5)}
        </div>
      </div>

      {/* Location */}
      {slot.location?.locName && (
        <div style={{ fontSize: '13px', color: 'var(--text-secondary)', fontWeight: 600, marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '4px' }}>
          📍 {slot.location.locName}
        </div>
      )}

      {/* Seats + Book button */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontSize: '11px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 600 }}>Seats</div>
          <div style={{ fontSize: '14px', fontWeight: 700, color: isAvailable ? 'var(--green)' : isHousefull ? 'var(--gold)' : 'var(--red)' }}>
            {isCancelled ? 'Cancelled' : isHousefull ? 'Housefull' : `${slot.seatsLeft} left`}
          </div>
        </div>
        <button
          onClick={onBook}
          disabled={!canBook}
          className="btn btn-primary btn-sm"
          style={{
            ...buttonStyle,
            cursor: canBook ? 'pointer' : 'not-allowed',
          }}
        >
          {buttonLabel}
        </button>
      </div>
    </div>
  );
};

// ── Detail label ──────────────────────────────────────────────────────────────
const Detail = ({ label, value }) => (
  <div>
    <div style={{ fontSize: '11px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.6px', fontWeight: 600 }}>{label}</div>
    <div style={{ fontSize: '14px', fontWeight: 700, marginTop: '2px', color: 'var(--text-primary)' }}>{value}</div>
  </div>
);

export default EventDetailPage;
